import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { AddSystemService } from 'src/app/shared/services/add-system.service';
import { ApiService } from 'src/app/shared/services/api.service';

@Component({
  selector: 'npr-add-system-summary',
  templateUrl: './add-system-summary.component.html',
  styleUrls: ['./add-system-summary.component.scss']
})
export class AddSystemSummaryComponent implements OnInit {
  respArray: any[] = [];
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();
  isLoading:boolean = false;

  constructor(private apiService: AddSystemService, 
              private router: Router,
              private cdr:ChangeDetectorRef) { }

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength : 5,
      columnDefs: [ { type: 'date', 'targets': [6] } ],
      order: [[6, 'desc']],
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]],
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],

    };
    
    this.getDataForMonitor();
  }
  getDataForMonitor() {
    this.isLoading = true;
    this.apiService.fecthingAddSystem().subscribe(dataresp => {
      this.respArray = dataresp;
      this.isLoading = false;
      this.cdr.markForCheck();

      this.dtTrigger.next();
    });
  }
  ngOnDestroy(): void {
    this.dtTrigger.unsubscribe();
  }
  getResp(data){
    console.log(data)
    this.apiService.setIndex({
      index: data.systemId,
    });
    this.router.navigateByUrl("/addSystem");
  }
  new(){
   
    this.apiService.setIndex({
      index: "",
    });
    this.router.navigateByUrl("/addSystem");
  }

}
